function getEscalationMinutes(riskLevel) {
  const aestHour = (new Date().getUTCHours() + 10) % 24;
  const businessHours = aestHour >= 8 && aestHour < 18;
  const table = {
    CRITICAL: { business: 30, after: 30 },
    HIGH:     { business: 60, after: 30 },
    MEDIUM:   { business: 120, after: 60 },
    LOW:      { business: null, after: null }
  };
  const t = table[riskLevel] || table.HIGH;
  return businessHours ? t.business : t.after;
}

const data = $input.first().json.body || $input.first().json;
const analysis = data.analysis || {};
const riskLevel = analysis.risk_level || data.severity || 'HIGH';
const riskEmoji = {
  'CRITICAL': '🔴',
  'HIGH': '🟠',
  'MEDIUM': '🟡',
  'LOW': '🟢'
}[riskLevel] || '⚪';
const confidencePct = Math.round((analysis.confidence || 0) * 100);
const alertId = `alert_${Date.now()}`;

return [{
  json: {
    alert_id: alertId,
    escalation_minutes: getEscalationMinutes(riskLevel) ?? (data.escalation_minutes || 30),
    risk_level: riskLevel,
    risk_emoji: riskEmoji,
    src_ip: data.src_ip || 'Unknown',
    block_duration_hours: analysis.block_duration_hours || 2,
    threat_type: analysis.threat_type || 'Unknown',
    mitre: analysis.mitre_technique || data.mitre || 'Unknown',
    anomaly_score: data.anomaly_score || 'N/A',
    confidence_pct: confidencePct,
    analysis_summary: analysis.summary || 'No summary available.',
    timestamp_aest: data.timestamp_aest || new Date().toISOString(),
    recommended_action: analysis.recommended_action || 'block_ip'
  }
}];

