const data = $input.first().json;
console.log(`Admin already responded (${data.admin_action}) for ${data.alert_id} — skipping auto escalation`);
return [{ json: { status: 'skipped', reason: 'admin_responded', action: data.admin_action } }];

const alertId = $('Prepare Data').first().json.alert_id;
let respondedFlag = 0;
let adminAction = 'none';

try {
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: `http://127.0.0.1:5680/flag/${alertId}`,
    json: true
  });
  if (response.found) {
    respondedFlag = 1;
    adminAction = response.data.action;
  }
} catch (e) {
  console.log('Error checking flag:', e.message);
}

const baseData = $('Prepare Data').first().json;

return [{ json: { ...baseData, responded_flag: respondedFlag, admin_action: adminAction } }];
